    CONSTRAINT "Enrollment_pkey" PRIMARY KEY ("id")
);
CREATE INDEX "Enrollment_userId_packageVersionId_idx"
    ON "Enrollment"("userId", "packageVersionId");
CREATE INDEX "Enrollment_packageVersionId_idx" ON "Enrollment"("packageVersionId");
CREATE INDEX "Enrollment_status_idx" ON "Enrollment"("status");
ALTER TABLE "Enrollment"
    ADD CONSTRAINT "Enrollment_userId_fkey"
    FOREIGN KEY ("userId") REFERENCES "User"("id")
    ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "Enrollment"
    ADD CONSTRAINT "Enrollment_packageVersionId_fkey"
    FOREIGN KEY ("packageVersionId") REFERENCES "PackageVersion"("id")
    ON DELETE RESTRICT ON UPDATE CASCADE;

CREATE TABLE "NodeTraversal" (
    "id" TEXT NOT NULL,
