);
CREATE INDEX "NodeTraversal_enrollmentId_idx" ON "NodeTraversal"("enrollmentId");
CREATE INDEX "NodeTraversal_decisionNodeId_idx" ON "NodeTraversal"("decisionNodeId");
ALTER TABLE "NodeTraversal"
    ADD CONSTRAINT "NodeTraversal_enrollmentId_fkey"
