    ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "NodeTraversal"
    ADD CONSTRAINT "NodeTraversal_decisionNodeId_fkey"
    FOREIGN KEY ("decisionNodeId") REFERENCES "DecisionNode"("id")
    ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "NodeTraversal"
    ADD CONSTRAINT "NodeTraversal_branchId_fkey"
    FOREIGN KEY ("branchId") REFERENCES "Branch"("id")
    ON DELETE SET NULL ON UPDATE CASCADE;

CREATE TABLE "StageAttempt" (
    "id" TEXT NOT NULL,
    "enrollmentId" TEXT NOT NULL,
    "stageRef" TEXT NOT NULL,
    "answer" JSONB NOT NULL,
    "branchId" TEXT,
    "score" DOUBLE PRECISION,
    "passed" BOOLEAN NOT NULL DEFAULT false,
