);
CREATE INDEX "StageAttempt_enrollmentId_stageRef_idx"
    ON "StageAttempt"("enrollmentId", "stageRef");
CREATE INDEX "StageAttempt_createdAt_idx" ON "StageAttempt"("createdAt");
ALTER TABLE "StageAttempt"
    ADD CONSTRAINT "StageAttempt_enrollmentId_fkey"
    FOREIGN KEY ("enrollmentId") REFERENCES "Enrollment"("id")
    ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "StageAttempt"
    ADD CONSTRAINT "StageAttempt_branchId_fkey"
    FOREIGN KEY ("branchId") REFERENCES "Branch"("id")
    ON DELETE SET NULL ON UPDATE CASCADE;

CREATE TABLE "Submission" (
    "id" TEXT NOT NULL,
    "stageAttemptId" TEXT NOT NULL,
    "bundleObjectKey" TEXT NOT NULL,
    "bundleSha" TEXT NOT NULL,
    "byteSize" INTEGER NOT NULL,
    "fileCount" INTEGER NOT NULL,
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT "Submission_pkey" PRIMARY KEY ("id")
);
CREATE INDEX "Submission_stageAttemptId_idx" ON "Submission"("stageAttemptId");
CREATE INDEX "Submission_bundleSha_idx" ON "Submission"("bundleSha");
ALTER TABLE "Submission"
    ADD CONSTRAINT "Submission_stageAttemptId_fkey"
    FOREIGN KEY ("stageAttemptId") REFERENCES "StageAttempt"("id")
    ON DELETE RESTRICT ON UPDATE CASCADE;

CREATE TABLE "Run" (
    "id" TEXT NOT NULL,
    "submissionId" TEXT NOT NULL,
    "status" TEXT NOT NULL,
    "runnerMode" TEXT NOT NULL,
    "logObjectKey" TEXT,
    "metricsJson" JSONB,
    "startedAt" TIMESTAMP(3),
    "finishedAt" TIMESTAMP(3),
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT "Run_pkey" PRIMARY KEY ("id")
);
CREATE INDEX "Run_submissionId_idx" ON "Run"("submissionId");
CREATE INDEX "Run_status_createdAt_idx" ON "Run"("status", "createdAt");
ALTER TABLE "Run"
    ADD CONSTRAINT "Run_submissionId_fkey"
    FOREIGN KEY ("submissionId") REFERENCES "Submission"("id")
    ON DELETE RESTRICT ON UPDATE CASCADE;

CREATE TABLE "Grade" (
    "id" TEXT NOT NULL,
    "stageAttemptId" TEXT NOT NULL,
    "submissionId" TEXT,
    "rubricVersion" TEXT NOT NULL,
    "evaluatorVersion" TEXT NOT NULL,
    "passed" BOOLEAN NOT NULL DEFAULT false,
    "score" DOUBLE PRECISION,
    "dimensions" JSONB NOT NULL,
    "evidenceRefs" JSONB NOT NULL,
    "modelMeta" JSONB,
    "history" JSONB NOT NULL DEFAULT '[]',
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT "Grade_pkey" PRIMARY KEY ("id")
);
CREATE UNIQUE INDEX "Grade_submissionId_rubricVersion_evaluatorVersion_key"
    ON "Grade"("submissionId", "rubricVersion", "evaluatorVersion");
CREATE INDEX "Grade_stageAttemptId_idx" ON "Grade"("stageAttemptId");
CREATE INDEX "Grade_createdAt_idx" ON "Grade"("createdAt");
ALTER TABLE "Grade"
    ADD CONSTRAINT "Grade_stageAttemptId_fkey"
    FOREIGN KEY ("stageAttemptId") REFERENCES "StageAttempt"("id")
    ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "Grade"
    ADD CONSTRAINT "Grade_submissionId_fkey"
    FOREIGN KEY ("submissionId") REFERENCES "Submission"("id")
    ON DELETE SET NULL ON UPDATE CASCADE;

-- =============================================================================
-- Mentor
-- =============================================================================

CREATE TABLE "MentorThread" (
    "id" TEXT NOT NULL,
    "enrollmentId" TEXT NOT NULL,
    "stageRef" TEXT NOT NULL,
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT "MentorThread_pkey" PRIMARY KEY ("id")
);
CREATE INDEX "MentorThread_enrollmentId_stageRef_idx"
    ON "MentorThread"("enrollmentId", "stageRef");
ALTER TABLE "MentorThread"
    ADD CONSTRAINT "MentorThread_enrollmentId_fkey"
    FOREIGN KEY ("enrollmentId") REFERENCES "Enrollment"("id")
    ON DELETE CASCADE ON UPDATE CASCADE;

CREATE TABLE "MentorMessage" (
    "id" TEXT NOT NULL,
    "threadId" TEXT NOT NULL,
    "role" TEXT NOT NULL,
    "bodyText" TEXT NOT NULL,
    "modelTier" TEXT,
    "modelId" TEXT,
    "provider" TEXT,
    "promptTokens" INTEGER,
    "completionTokens" INTEGER,
    "redactionTriggered" BOOLEAN NOT NULL DEFAULT false,
    "flagged" BOOLEAN NOT NULL DEFAULT false,
