    CONSTRAINT "MentorMessage_pkey" PRIMARY KEY ("id")
);
CREATE INDEX "MentorMessage_threadId_createdAt_idx"
    ON "MentorMessage"("threadId", "createdAt");
CREATE INDEX "MentorMessage_flagged_idx" ON "MentorMessage"("flagged");
ALTER TABLE "MentorMessage"
    ADD CONSTRAINT "MentorMessage_threadId_fkey"
    FOREIGN KEY ("threadId") REFERENCES "MentorThread"("id")
    ON DELETE CASCADE ON UPDATE CASCADE;

-- =============================================================================
-- Analytics & sharing
-- =============================================================================

CREATE TABLE "BranchStat" (
    "id" TEXT NOT NULL,
    "packageVersionId" TEXT NOT NULL,
    "decisionNodeId" TEXT NOT NULL,
    "branchId" TEXT NOT NULL,
    "cohort" TEXT NOT NULL,
    "windowStart" TIMESTAMP(3) NOT NULL,
    "windowEnd" TIMESTAMP(3) NOT NULL,
    "n" INTEGER NOT NULL,
    "percent" DOUBLE PRECISION,
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT "BranchStat_pkey" PRIMARY KEY ("id")
);
CREATE INDEX "BranchStat_packageVersionId_decisionNodeId_branchId_cohort__idx"
    ON "BranchStat"("packageVersionId", "decisionNodeId", "branchId", "cohort", "windowStart");
ALTER TABLE "BranchStat"
    ADD CONSTRAINT "BranchStat_packageVersionId_fkey"
    FOREIGN KEY ("packageVersionId") REFERENCES "PackageVersion"("id")
    ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "BranchStat"
    ADD CONSTRAINT "BranchStat_decisionNodeId_fkey"
    FOREIGN KEY ("decisionNodeId") REFERENCES "DecisionNode"("id")
    ON DELETE CASCADE ON UPDATE CASCADE;

CREATE TABLE "ShareCard" (
    "id" TEXT NOT NULL,
