    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT "ShareCard_pkey" PRIMARY KEY ("id")
);
CREATE UNIQUE INDEX "ShareCard_publicSlug_key" ON "ShareCard"("publicSlug");
CREATE INDEX "ShareCard_userId_idx" ON "ShareCard"("userId");
CREATE INDEX "ShareCard_enrollmentId_idx" ON "ShareCard"("enrollmentId");
CREATE INDEX "ShareCard_packageVersionId_idx" ON "ShareCard"("packageVersionId");
ALTER TABLE "ShareCard"
    ADD CONSTRAINT "ShareCard_userId_fkey"
    FOREIGN KEY ("userId") REFERENCES "User"("id")
    ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "ShareCard"
    ADD CONSTRAINT "ShareCard_enrollmentId_fkey"
    FOREIGN KEY ("enrollmentId") REFERENCES "Enrollment"("id")
    ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "ShareCard"
    ADD CONSTRAINT "ShareCard_packageVersionId_fkey"
    FOREIGN KEY ("packageVersionId") REFERENCES "PackageVersion"("id")
